import avatar from "../assets/Images/avatar.svg"
function Body() {
  return (
    <>
      <div className="container-top">
        <div className="picture">
          <div className="avatar">
            <img src={avatar} alt="" />
          </div>
          
        </div>
      </div>
    </>
  )
}
export default Body;
